def perceive(data):
    acuity = None
    if isinstance(data, dict):
        acuity = data.get("acuity")
    else:
        text = str(data).lower()
        # prefer the number written after the word 'acuity'
        if "acuity" in text:
            tail = text.split("acuity", 1)[1]
            num = ""
            for ch in tail:
                if ch.isdigit():
                    num += ch
                elif num:
                    break
            if num:
                acuity = int(num)
        # otherwise take the first standalone integer in the note
        if acuity is None:
            for token in text.replace(",", " ").replace(":", " ").split():
                if token.isdigit():
                    acuity = int(token)
                    break
    if acuity is None:
        return {}
    acuity = int(acuity)
    if acuity < 1:
        acuity = 1
    if acuity > 5:
        acuity = 5
    return {"pending_acuity": acuity}
